import Post from './Post';
import { useState, useEffect, Fragment } from 'react';
import { useSelector } from 'react-redux';

let AllPosts = ({ allPosts, setAllPosts }) => {

   const [isLoading, setIsLoading] = useState(false)
   let userData = useSelector((state) => state.userReducer.userParams);

   useEffect(() => {
      if (userData.id) {
         fetch(`${process.env.REACT_APP_SERVER_PATH}api/post/${userData.id}`)
            .then(res => res.json())
            .then(getData => setAllPosts([...getData]))
            .catch(e => console.log(e))
      }
   }, [userData])

   return (
      <div className="page__posts-all posts-all">

         {
            !isLoading
               ?
               <Fragment>
                  {
                     allPosts.length
                        ?
                        allPosts.map((item) => {
                           return (
                              <Post
                                 key={item.id}
                                 postData={item}
                                 setAllPosts={setAllPosts}
                                 setIsLoading={setIsLoading}
                              />
                           )
                        })
                        :
                        <div className="posts-all__empty">
                           <div className="posts-all__empty-icon">
                              <img src="./images/write.png" className="posts-all__empty-img" alt="empty" />
                           </div>
                           <p className="posts-all__empty-title">No posts yet 🙁</p>
                        </div>
                  }
               </Fragment>
               :
               <div id="floatingCirclesG">
                  <div className="f_circleG" id="frotateG_01"></div>
                  <div className="f_circleG" id="frotateG_02"></div>
                  <div className="f_circleG" id="frotateG_03"></div>
                  <div className="f_circleG" id="frotateG_04"></div>
                  <div className="f_circleG" id="frotateG_05"></div>
                  <div className="f_circleG" id="frotateG_06"></div>
                  <div className="f_circleG" id="frotateG_07"></div>
                  <div className="f_circleG" id="frotateG_08"></div>
               </div>
         }
      </div>
   );
}

export default AllPosts;