import { useState, Fragment } from 'react';
import { useForm } from 'react-hook-form';
import { useDispatch, useSelector } from 'react-redux';
import { changeUserAction } from '../../store/userReducer';

const EditModal = ({ stateModal, setModal }) => {

   let userData = useSelector((state) => state.userReducer.userParams)
   const dispatch = useDispatch()
   const [isLoading, setIsLoading] = useState(false)

   const {
      register,
      watch,
      formState: { errors },
      handleSubmit,
   } = useForm({ mode: "onChange" });

   //следит за состоянием input'a с файлом
   const watchImg = watch("img");

   const onSubmit = async (data) => {

      // проверяем заполнены ли поля в объекте
      let checkChange = Object.keys({ ...data }).reduce((value, item) => {
         if (!data[item].length) {
            if (item === 'img' && data[item].length) {
               return
            }
            return value + 1
         }
         return value
      }, 0)

      // если нет хоть 1 заполненного поля, то прекращаем функцию
      if (checkChange === 5) {
         alert('Вы не изменили ни одного поля.')
         setModal(!stateModal)
         return
      }

      const changeUser = { ...data }
      changeUser.user_id = userData.id

      // промис для того, чтобы отсылать запрос на сервер только при завершении кодирования в 64 формат картинки
      const promise = new Promise((resolve, reject) => {
         // проверка есть ли добавленный файл
         if (changeUser.img.length) {
            // переводим картинку в 64 байтный формат
            const reader = new FileReader();
            reader.readAsDataURL(changeUser.img[0])
            reader.onloadend = () => {
               changeUser.img = reader.result
               resolve()
            }
         } else { resolve() }
      })
         .then(async () => {

            try {
               setIsLoading(true)
               //обновление юзера в бд
               const changeDB = await fetch(`${process.env.REACT_APP_SERVER_PATH}api/user`, {
                  method: 'PUT',
                  body: JSON.stringify(changeUser),
                  headers: { 'content-type': 'application/json' }
               })

               const getRespose = await changeDB.json()

               dispatch(changeUserAction(getRespose))

               setIsLoading(false)

               setModal(false)

               document.body.style.overflow = "visible"

            } catch (e) {
               alert(e)
            }
         })
   }


   return (
      <div className='modal-wrapper'>
         <div onClick={e => e.stopPropagation()} className='modal-edit'>
            <p className='modal-edit__title'>Edit profile</p>
            {
               !isLoading
                  ?
                  <Fragment>
                     <form onSubmit={handleSubmit(onSubmit)} className='modal-edit__form' id='form_edit'>

                        <label className='modal-edit__label'>
                           Name
                           <input
                              {...register('name', {
                                 pattern: { value: /^[a-zA-Z]+$/, message: "Некорректные символы." },
                                 maxLength: { value: 20, message: "Максимум 20 символов" }
                              })}
                              className='modal-edit__input' type="text" placeholder={userData.name}
                           />
                           <p className={`modal-edit__error ${errors.name ? '_active' : null}`}>
                              {errors?.name?.message || 'Обязательное поле для ввода.'}
                           </p>
                        </label>

                        <label className='modal-edit__label'>
                           Surname
                           <input
                              {...register('surname', {
                                 pattern: { value: /^[a-zA-Z]+$/, message: "Некорректные символы." },
                                 maxLength: { value: 20, message: "Максимум 20 символов" }
                              })}
                              className='modal-edit__input' type="text" placeholder={userData.surname}
                           />
                           <p className={`modal-edit__error ${errors.surname ? '_active' : null}`}>
                              {errors?.surname?.message || 'Обязательное поле для ввода.'}
                           </p>
                        </label>

                        <label className='modal-edit__label'>
                           Date of birth
                           <input
                              {...register('birth')}
                              className='modal-edit__input' type="date" min="1960-01-01" max="2015-01-01"
                           />
                           <p className={`modal-edit__error ${errors.birth ? '_active' : null}`}>
                              {errors?.birth?.message || 'Обязательное поле для ввода.'}
                           </p>
                        </label>

                        <label className='modal-edit__label'>
                           City
                           <input
                              {...register('city', {
                                 pattern: { value: /^[a-zA-Z]+$/, message: "Некорректные символы." },
                                 maxLength: { value: 20, message: "Максимум 20 символов" }
                              })}
                              className='modal-edit__input' type="text" placeholder={userData.city}
                           />
                           <p className={`modal-edit__error ${errors.city ? '_active' : null}`}>
                              {errors?.city?.message || 'Обязательное поле для ввода.'}
                           </p>
                        </label>

                        <div className={watchImg?.length ? 'modal-edit__photo-container _active' : 'modal-edit__photo-container'}>
                           <label className='modal-edit__photo-label'>
                              Add photo
                              <input
                                 {...register('img')}
                                 className='modal-edit__photo-input' type="file"
                              />
                           </label>
                           <p className={`modal-edit__error ${errors.img ? '_active' : null}`}>
                              {errors?.img?.message || 'Обязательное поле для ввода.'}
                           </p>
                        </div>

                     </form>
                     <button className="modal-edit__button-submit" form='form_edit'>CHANGE</button>
                     <button onClick={e => {
                        document.body.style.overflow = "visible"
                        setModal(!stateModal)
                     }} type='button' className="modal-edit__button-close"></button>
                  </Fragment>
                  :
                  <div id="floatingCirclesG">
                     <div className="f_circleG" id="frotateG_01"></div>
                     <div className="f_circleG" id="frotateG_02"></div>
                     <div className="f_circleG" id="frotateG_03"></div>
                     <div className="f_circleG" id="frotateG_04"></div>
                     <div className="f_circleG" id="frotateG_05"></div>
                     <div className="f_circleG" id="frotateG_06"></div>
                     <div className="f_circleG" id="frotateG_07"></div>
                     <div className="f_circleG" id="frotateG_08"></div>
                  </div>
            }
         </div>
      </div>
   );
}

export default EditModal;