import { Fragment } from 'react';
import { Route, Routes } from 'react-router-dom';
import { useSelector } from 'react-redux';

import AuthorizationPage from '../../pages/AuthorizationPage/AuthorizationPage';
import MainPage from '../../pages/MainPage/MainPage';
import GeneralLayout from '../../pages/GeneralLayout/GeneralLayout';
import FriendsPage from '../../pages/FriendsPage/FriendsPage';
import MessagesPage from '../../pages/MessagesPage/MessagesPage';
import ChatPage from '../../pages/ChatPage/ChatPage';
import NewsPage from '../../pages/NewsPage/NewsPage';
import PhotosPage from '../../pages/PhotosPage/PhotosPage';
import SearchPage from '../../pages/SearchPage/SearchPage';
import PersonPage from '../../pages/PersonPage/PersonPage';

const MyRoutes = () => {

   const userAutho = useSelector((state) => state.authReducer.authorization)

   return (
      <Routes>
         {
            userAutho
               ?
               <Fragment>
                  <Route path='/' element={<GeneralLayout />}>
                     <Route index element={<MainPage />} />
                     <Route path='/page/:username' element={<PersonPage />} />
                     <Route path='/friends' element={<FriendsPage />} />
                     <Route path='/messages' element={<MessagesPage />} />
                     <Route path='/messages/:id' element={<ChatPage />} />
                     <Route path='/news' element={<NewsPage />} />
                     <Route path='/photos' element={<PhotosPage />} />
                     <Route path='/search' element={<SearchPage />} />
                     <Route path='*' element={<MainPage />} />
                  </Route>
               </Fragment>
               :
               <Fragment>
                  <Route path='/autho' element={<AuthorizationPage />} />
                  <Route path='*' element={<AuthorizationPage />} />
               </Fragment>
         }

      </Routes>
   );
}

export default MyRoutes;