import './MainPage.scss'
import { useSelector } from 'react-redux';
import { useState } from 'react';
import { useOutletContext } from 'react-router-dom';
import Info from '../../components/MainPage/Info';
import NewPost from '../../components/MainPage/NewPost';
import AllPosts from '../../components/MainPage/AllPosts';

const MainPage = () => {

   const [scroll, setScroll] = useOutletContext();

   const userData = useSelector((state) => state.userReducer.userParams)

   const [allPosts, setAllPosts] = useState([])
   const [allPhotos, setAllPhotos] = useState([])

   return (
      <div className="main__content page">
         <div className="page__top-container">
            <div className="page__avatar">
               <img src={userData.img ? `https://res.cloudinary.com/daggdfi3i/image/upload/${userData.img}.jpg` : null} className="page__avatar-image" alt="avatar" />
            </div>
            <Info
               allPosts={allPosts}
               allPhotos={allPhotos}
               setAllPhotos={setAllPhotos}
            />
         </div>
         <div className="page__bottom-container">
            <NewPost
               setAllPosts={setAllPosts}
            />
            <AllPosts
               allPosts={allPosts}
               setAllPosts={setAllPosts}
            />
         </div>
      </div>
   );
}

export default MainPage;