import { useEffect, useState } from 'react';
import { useSelector } from 'react-redux';

const Like = ({ postData }) => {

   const userData = useSelector((state) => state.userReducer.userParams);
   const [likes, setLikes] = useState([])

   // получаем список лайков с сервера для данного поста
   useEffect(() => {
      fetch(`https://deploy-social.herokuapp.com/api/post/like/${postData.id}`)
         .then(res => res.json())
         .then(getData => setLikes([...getData]))
         .catch(e => console.log(e))
   }, [])

   const checkLike = () => {
      if (likes.length) {
         // перебираем лайки поста, если есть объект с id текущего пользователя, который просматривает страницу, то запрещаем ему ставить лайк
         for (let i of likes) {
            if (i.user_id === userData.id) {
               return "posts-item__likes _active"
            }
         }
         return "posts-item__likes"
      } else {
         return "posts-item__likes"
      }
   }

   // по id поста и id user'a который ставит лайк, мы создаем новый лайк в бд
   const likePost = async () => {

      const likeData = {
         user_id: userData.id,
         post_id: postData.id
      }

      try {

         const createLike = await fetch(`${process.env.REACT_APP_SERVER_PATH}api/post/like`, {
            method: 'POST',
            body: JSON.stringify(likeData),
            headers: { 'content-type': 'application/json' }
         })

         const allLikes = await createLike.json()
         setLikes([...allLikes])

      } catch (error) {
         console.log(error)
      }
   }

   return (
      <div onClick={() => likePost()} className={checkLike()}>
         <div className="posts-item__likes-icon"></div>
         <div className="posts-item__likes-number">{likes.length}</div>
      </div>
   );
}

export default Like;