import { useState } from 'react';
import { useSelector } from 'react-redux';

const Search = ({ setFoundUsers, setIsLoading }) => {

   const userData = useSelector((state) => state.userReducer.userParams)
   const [inputId, setInputId] = useState('')

   const findAll = () => {
      setIsLoading(true)

      fetch(`${process.env.REACT_APP_SERVER_PATH}api/search/${userData.id}`)
         .then(res => res.json())
         .then(getData => setFoundUsers([...getData]))
         .catch(e => console.log(e))
         .finally(() => setIsLoading(false))
   }

   const findOne = () => {

      if (inputId.length && inputId != userData.username) {
         setIsLoading(true)

         fetch(`${process.env.REACT_APP_SERVER_PATH}api/search/one/${inputId}`)
            .then(res => res.json())
            .then(getData => {
               if (getData.length) {
                  setFoundUsers([...getData])
               } else {
                  alert('Данного пользователя не найдено. Проверьте правильность написания id.')
               }
            })
            .catch(e => alert(e))
            .finally(() => setIsLoading(false))
      } else {
         alert('Вы не ввели id, или ввели свой.')
      }
   }

   return (
      <div className="search__handler">
         <button onClick={() => findAll()} className="search__button-all">All</button>
         <input onChange={(e) => setInputId(e.target.value)} value={inputId} className="search__input" type="text" placeholder="Write id"></input>
         <button onClick={() => findOne()} className="search__button-find">Search</button>
      </div>
   );
}

export default Search;