import { useDispatch } from 'react-redux';
import { useForm } from 'react-hook-form';
import { getUserActionThunk } from '../../store/userReducer';

let AuthorizationForm = ({ tabsState, setLoading }) => {

   const dispatch = useDispatch()

   const {
      register,
      formState: { errors },
      handleSubmit,
   } = useForm({ mode: "onChange" });

   const onSubmit = async (data) => {

      try {
         setLoading(true)

         const sendCheck = await fetch(`${process.env.REACT_APP_SERVER_PATH}api/user/check`, {
            method: 'POST',
            headers: {
               'Content-Type': 'application/json;charset=utf-8'
            },
            body: JSON.stringify(data)
         })
         const getCheck = await sendCheck.json()

         setLoading(false)

         // если данные правильные, и пришел ответ с сервера
         if (getCheck) {
            localStorage.setItem('username', data.username)
            dispatch(getUserActionThunk())
            dispatch({ type: "CHANGE_AUTHO" })
         } else {
            alert('Данного пользователя не существует. Проверьте правильность введенных данных')
         }

      } catch (error) {
         console.log(error)
      }

   }


   return (
      <form onSubmit={handleSubmit(onSubmit)} className={tabsState.auth ? "entry__form-authorize form-authorize _active" : "entry__form-authorize form-authorize"}>

         <label className='form-authorize__label'>
            Username
            <input
               {...register('username', {
                  required: true,
                  pattern: { value: /^[0-9a-z]+$/, message: "Некорректные символы." },
                  minLength: { value: 4, message: "Минимум 4 символа." },
                  maxLength: { value: 10, message: "Максимум 10 символов" }
               })}
               className='form-authorize__input' type="text" placeholder="Your username"
            />
            <p className={`form-authorize__error ${errors.username ? '_active' : null}`}>
               {errors?.username?.message || 'Обязательное поле для ввода.'}
            </p>
         </label>

         <label className='form-authorize__label'>
            Password
            <input
               {...register('password', {
                  required: true,
                  pattern: { value: /^[a-zA-Z0-9]+$/, message: "Некорректные символы." },
                  minLength: { value: 6, message: "Минимум 6 символов" },
                  maxLength: { value: 20, message: "Максимум 20 символов" }
               })}
               className='form-authorize__input' type="password" placeholder="Your password"
            />
            <p className={`form-authorize__error ${errors.password ? '_active' : null}`}>
               {errors?.password?.message || 'Обязательное поле для ввода.'}
            </p>
         </label>

         <button type='submit' className="form-authorize__button-submit" >AUTHORIZATION</button>
      </form>
   );
}

export default AuthorizationForm;