
const userData = { userParams: {} }

// функция которая изменяет наш redux-стейт по написанной логике. Данные берутся из переданного action
export const userReducer = (state = userData, action) => {
   switch (action.type) {
      case "CREATE_USER":
         return { ...state, userParams: { ...action.payload } }
      case "CHANGE_USER":
         return { ...state, userParams: { ...action.payload } }
      default:
         return state
   }
}

export const CreateUserActionThunk = (data) => {
   return (dispatch) => {
      try {
         setTimeout(() => {
            fetch(`${process.env.REACT_APP_SERVER_PATH}api/user`, {
               method: 'POST',
               body: JSON.stringify(data),
               headers: { 'content-type': 'application/json' }
            })
               .then(res => res.json())
               .then(getData => {
                  // добавляем полученные данные пользователя в redux
                  dispatch({ type: "CREATE_USER", payload: getData })
                  // записываем id пользователя в localStorage
                  localStorage.setItem('username', getData.username)
                  dispatch({ type: "CHANGE_AUTHO" })
               })
         }, 3000)
      } catch (e) {
         alert(e)
      }
   }
}

export const getUserActionThunk = () => {

   const username = localStorage.getItem('username')

   return (dispatch) => {
      fetch(`${process.env.REACT_APP_SERVER_PATH}api/user/${username}`)
         .then(res => res.json())
         .then(getData => {
            // добавляем полученные данные пользователя в redux
            dispatch({ type: "CREATE_USER", payload: getData })
         })
         .catch(e => console.log(e))
   }
}

export const changeUserAction = (payload) => ({ type: "CHANGE_USER", payload })

