import Like from './Like';

let Post = ({ postData, setAllPosts, setIsLoading }) => {

   // логика кнопки по удалению поста
   let deletePost = async () => {

      try {
         
         setIsLoading(true)
         const getPosts = await fetch(`${process.env.REACT_APP_SERVER_PATH}api/post/${postData.id}`, { method: 'DELETE' })
         const posts = await getPosts.json()
         setAllPosts([...posts])
         setIsLoading(false)

      } catch (error) {
         console.log(error)
      }
   }

   return (
      <div className="posts-all__item posts-item">
         <div className="posts-item__top">
            <div className="posts-item__data">{postData.date}</div>
            <div onClick={() => deletePost()} className="posts-item__delete"></div>
         </div>
         <div className="posts-item__content">
            <p className="posts-item__text">{postData.text}</p>
            {
               postData.img_post.length
                  ?
                  <div className="posts-item__img-container">
                     <img src={`https://res.cloudinary.com/daggdfi3i/image/upload/${postData?.img_post}.jpg`} className="posts-item__img" alt="Post pic" />
                  </div>
                  :
                  null
            }
         </div>
         <div className="posts-item__bottom">
            <Like postData={postData} />
         </div>
      </div>
   );
}

export default Post;