import { useSelector } from 'react-redux';
import MessageButton from '../UI/MessageButton/MessageButton';

let Buttons = ({ userInfo, friendStatus, setFriendStatus }) => {

   let userData = useSelector((state) => state.userReducer.userParams)

   const handlerFriend = async () => {

      if (userData.id) {
         // при отправке заявки в друзья, когда еще не созданы данные
         if (!friendStatus.length) {

            const newFriend = {
               user_id: userData.id,
               friend_id: userInfo.id
            }

            const createFriendBase = await fetch(`${process.env.REACT_APP_SERVER_PATH}api/friend`, {
               method: 'POST',
               headers: { 'Content-Type': 'application/json' },
               body: JSON.stringify(newFriend)
            })

            const friendStatus = await createFriendBase.json()
            setFriendStatus(friendStatus)

         } else if (friendStatus === 'request') {
            // логика когда ты принимаешь заявку в друзья, находясь на странице пользователя. Меняется статус дружбы в таблице на сервере
            let newStatus = {
               user_id: userData.id,
               friend_id: userInfo.id,
               status: 'friend'
            }

            const updateStatus = await fetch(`${process.env.REACT_APP_SERVER_PATH}api/friend/status`, {
               method: 'PUT',
               headers: { 'Content-Type': 'application/json' },
               body: JSON.stringify(newStatus)
            })

            const friendStatus = await updateStatus.json()
            setFriendStatus(friendStatus)
         }
      }
   }

   return (
      <div className="person__actions-buttons">
         <MessageButton
            data={userInfo}
            classTitle={'person__button-write'}
            typeName={'button'}
         />
         <button onClick={() => handlerFriend()} className={!friendStatus.length ? "person__button-add" : `person__button-add _${friendStatus}`}></button>
      </div>
   );
}

export default Buttons;