import './MessagesPage.scss';
import { useState, useEffect, Fragment } from 'react';
import { useSelector } from 'react-redux';
import Chat from '../../components/MessagesPage/Chat'

const MessagesPage = () => {

   const userData = useSelector((state) => state.userReducer.userParams)
   const [chats, setChats] = useState([])
   const [isLoading, setIsLoading] = useState(false)

   // получаем все чаты для пользователя
   useEffect(() => {
      if (userData.id) {
         setIsLoading(true)

         fetch(`${process.env.REACT_APP_SERVER_PATH}api/chat/all/${userData.id}`)
            .then(res => res.json())
            .then(getData => {
               setChats([...getData])
            })
            .catch(e => alert(e))
            .finally(() => setIsLoading(false))
      }
   }, [userData])

   return (
      <div className="main__content messages">
         <p className="messages__title">My messages</p>
         {
            !isLoading
               ?
               <Fragment>
                  {
                     chats.length
                        ?
                        <div className="messages__items">
                           {
                              chats.map((item) => {
                                 return (
                                    <Chat chatInfo={item} setChats={setChats} user_id={userData.id} key={item.interlocutor_img} />
                                 )
                              })
                           }
                        </div>
                        :
                        <div className="messages__empty">
                           <div className="messages__empty-icon">
                              <img src="./images/img_571116.png" className="messages__empty-img" alt="empty-pic" />
                           </div>
                           <p className="messages__empty-title">No messages yet 🙁</p>
                        </div>
                  }
               </Fragment>
               :
               <div id="floatingCirclesG">
                  <div className="f_circleG" id="frotateG_01"></div>
                  <div className="f_circleG" id="frotateG_02"></div>
                  <div className="f_circleG" id="frotateG_03"></div>
                  <div className="f_circleG" id="frotateG_04"></div>
                  <div className="f_circleG" id="frotateG_05"></div>
                  <div className="f_circleG" id="frotateG_06"></div>
                  <div className="f_circleG" id="frotateG_07"></div>
                  <div className="f_circleG" id="frotateG_08"></div>
               </div>
         }
      </div>
   );
}

export default MessagesPage;