import { useSelector } from 'react-redux';
import { Link } from 'react-router-dom';

const Request = ({ requestData, friendsList, setFriendsList }) => {

   const userData = useSelector((state) => state.userReducer.userParams)

   const rejectFriend = () => {
      fetch(`${process.env.REACT_APP_SERVER_PATH}api/friend/reject?user_id=${userData.id}&friend_id=${requestData.id}`, { method: 'DELETE', })
         .then(res => res.json())
         .then(getData => setFriendsList({ ...friendsList, requests: [...getData.requests] }))
         .catch(e => alert(e))
   }

   const acceptFriend = async () => {
      const newFriend = {
         user_id: userData.id,
         friend_id: requestData.id,
         status: 'friend'
      }

      try {
         const addFriend = await fetch(`${process.env.REACT_APP_SERVER_PATH}api/friend/accept`, {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(newFriend)
         })

         const allFriends = await addFriend.json()
         setFriendsList({ ...friendsList, friends: [...allFriends.friends], requests: [...allFriends.requests] })
      } catch (e) {
         console.log(e)
      }
   }

   return (
      <div className="friends__request request-item">
         <Link to={`/page/${requestData.username}`} className='request-item__link'>
            <div className="request-item__avatar">
               <img src={`https://res.cloudinary.com/daggdfi3i/image/upload/${requestData.img}`} className="request-item__avatar-img" alt="friend-avatar" />
            </div>
         </Link>
         <div className="request-item__content">
            <div className="request-item__name">
               <p className="request-item__forename">{requestData.name}</p>
               <p className="request-item__surname">{requestData.surname}</p>
            </div>
            <div className="request-item__buttons">
               <button onClick={() => acceptFriend()} type="button" className="request-item__button-accept">Accept</button>
               <button onClick={() => rejectFriend()} type="button" className="request-item__button-reject">Reject</button>
            </div>
         </div>
      </div>
   );
}

export default Request;