import './GeneralLayout.scss';
import { useEffect, useState, Fragment } from 'react';
import { Outlet, Link } from 'react-router-dom';
import { useDispatch, useSelector } from 'react-redux';
import { getUserActionThunk } from '../../store/userReducer';
import MyModal from '../../components/UI/MyModal/MyModal';
import EditModal from '../../components/GeneralLayout/EditModal';

let GeneralLayout = () => {

   const userData = useSelector((state) => state.userReducer.userParams)
   const dispatch = useDispatch()

   const [modal, setModal] = useState(false)

   let [scroll, setScroll] = useState(false)

   // // scroll объявляется при монтировании компонента
   // useEffect(() => {
   //    document.addEventListener('scroll', scrollPage)

   //    return function () {
   //       document.removeEventListener('scroll', scrollPage)
   //    }
   // }, [scroll])

   // const scrollPage = () => {

   //    if (window.scrollY >= 1 && scroll === false) {
   //       // вот тут я меняю стейт на true
   //       setScroll(true)
   //    } else if (window.scrollY < 1 && scroll === true) {
   //       setScroll(false)
   //    }
   // }



   useEffect(() => {
      // если userData пуст, то выполняем thunk
      if (!Object.keys(userData).length) {
         dispatch(getUserActionThunk())
      }
   }, [userData])

   const exit = () => {
      localStorage.removeItem('username')
      dispatch({ type: "CHANGE_AUTHO" })
   }

   return (
      <div className="wrapper">
         {
            !Object.keys(userData).length
               ?
               <div id="floatingCirclesG">
                  <div className="f_circleG" id="frotateG_01"></div>
                  <div className="f_circleG" id="frotateG_02"></div>
                  <div className="f_circleG" id="frotateG_03"></div>
                  <div className="f_circleG" id="frotateG_04"></div>
                  <div className="f_circleG" id="frotateG_05"></div>
                  <div className="f_circleG" id="frotateG_06"></div>
                  <div className="f_circleG" id="frotateG_07"></div>
                  <div className="f_circleG" id="frotateG_08"></div>
               </div>
               :
               <Fragment>
                  <div className="header">
                     <div className="header__container">
                        <div className="header__exit">
                           <button onClick={() => exit()} type="button" className="header__exit-button">Exit</button>
                        </div>
                        <Link to='/' className="header__logo">
                           <div className="header__logo-icon"></div>
                           <p className="header__logo-text">Social network</p>
                        </Link>
                        <button onClick={() => {
                           document.body.style.overflow = "hidden"
                           setModal(!modal)
                        }} className="header__settings"></button>
                     </div>
                  </div>
                  <div className="main">
                     <div className="main__container">
                        <aside className="main__aside main-aside">
                           <ul className="main-aside__list">
                              <li className="main-aside__item">
                                 <Link to="/" className="main-aside__link"></Link>
                              </li>

                              <li className="main-aside__item">
                                 <Link to="/news" className="main-aside__link"></Link>
                              </li>

                              <li className="main-aside__item">
                                 <Link to="/messages" className="main-aside__link"></Link>
                              </li>

                              <li className="main-aside__item">
                                 <Link to="/friends" className="main-aside__link"></Link>
                              </li>

                              <li className="main-aside__item">
                                 <Link to="/photos" className="main-aside__link"></Link>
                              </li>

                              <li className="main-aside__item">
                                 <Link to="/search" className="main-aside__link"></Link>
                              </li>
                           </ul>
                        </aside>
                        <Outlet context={[scroll, setScroll]} />
                     </div>
                  </div>
                  <MyModal stateModal={modal} setModal={setModal}>
                     <EditModal stateModal={modal} setModal={setModal} />
                  </MyModal>
               </Fragment>
         }
      </div>
   );
}

export default GeneralLayout;