import './PersonPage.scss';
import { useState, useEffect, Fragment } from 'react';
import { useSelector } from 'react-redux';
import Info from '../../components/PersonPage/Info';
import AllPosts from '../../components/PersonPage/AllPosts';
import Buttons from '../../components/PersonPage/Buttons';

const PersonPage = () => {

   const userData = useSelector((state) => state.userReducer.userParams)

   // вырезаем username из строки url адреса
   const username = document.location.pathname.slice(6)


   const [userInfo, setUserInfo] = useState({})
   const [allPosts, setAllPosts] = useState([])
   const [allPhotos, setAllPhotos] = useState([])
   const [friendStatus, setFriendStatus] = useState('')

   const [isLoading, setIsLoading] = useState(false)

   useEffect(async () => {
      setIsLoading(true)

      try {
         // при загрузке страницы подгружаем данные о пользователе из бд, по его username
         const requestUserData = await fetch(`${process.env.REACT_APP_SERVER_PATH}api/user/${username}`)
         const getUserData = await requestUserData.json()
         setUserInfo({ ...getUserData })

      } catch (error) {
         console.log(error)
      }

      setIsLoading(false)
   }, [userData.id])

   //получаем статус дружбы для текущего юзера по отношению к данной странице пользователя
   useEffect(async () => {

      try {

         if (Object.keys(userInfo).length && Object.keys(userData).length) {
            const requestFriendStatus = await fetch(`${process.env.REACT_APP_SERVER_PATH}api/friend/status?user_id=${userData.id}&friend_id=${userInfo.id}`)
            const friendStatus = await requestFriendStatus.json()
            setFriendStatus(friendStatus)
         }

      } catch (error) {
         console.log(error)
      }
   }, [userInfo])

   return (
      <div className="main__content person">
         {
            !isLoading
               ?
               <Fragment>
                  <div className="person__top-container">
                     <div className="person__actions">
                        <div className="person__avatar">
                           <img src={userInfo.img ? `https://res.cloudinary.com/daggdfi3i/image/upload/${userInfo?.img}.jpg` : null} className="person__avatar-image" alt="Page avatar" />
                        </div>
                        <Buttons
                           userInfo={userInfo}
                           friendStatus={friendStatus}
                           setFriendStatus={setFriendStatus}
                        />
                     </div>
                     <Info
                        userInfo={userInfo}
                        allPhotos={allPhotos}
                        allPosts={allPosts}
                        setAllPhotos={setAllPhotos}
                     />
                  </div>
                  <div className="person__bottom-container">
                     <AllPosts
                        userInfo={userInfo}
                        allPosts={allPosts}
                        setAllPosts={setAllPosts}
                     />
                  </div>
               </Fragment>
               :
               <div id="floatingCirclesG">
                  <div className="f_circleG" id="frotateG_01"></div>
                  <div className="f_circleG" id="frotateG_02"></div>
                  <div className="f_circleG" id="frotateG_03"></div>
                  <div className="f_circleG" id="frotateG_04"></div>
                  <div className="f_circleG" id="frotateG_05"></div>
                  <div className="f_circleG" id="frotateG_06"></div>
                  <div className="f_circleG" id="frotateG_07"></div>
                  <div className="f_circleG" id="frotateG_08"></div>
               </div>
         }
      </div>
   );
}

export default PersonPage;