import { useState, useEffect, useRef } from 'react';
import { useSelector } from 'react-redux';

const NewPost = ({ setAllPosts }) => {

   const userData = useSelector((state) => state.userReducer.userParams);

   const [isLoading, setIsLoading] = useState(false)
   const [newPost, setNewPost] = useState({
      text: "",
      img: "",
   });

   const [areaHeight, setAreaHeight] = useState(70)
   const heightClone = useRef()

   useEffect(() => {
      if (newPost.text === '') {
         setAreaHeight(70)
      } else if (heightClone.current.clientHeight > 70) {
         setAreaHeight(heightClone.current.clientHeight)
      }
   }, [newPost.text])

   const createPost = (event) => {
      event.preventDefault()

      const postData = {
         user_id: userData.id,
         name: userData.name,
         surname: userData.surname,
         text: newPost.text,
      }

      let dateMonth = new Date().toDateString().substr(4, 3)
      let dateDay = new Date().getDate();
      let dateYear = new Date().getFullYear();
      let dateHour = new Date().getHours();
      let dateMinute = new Date().getMinutes();

      postData.date = `${dateMonth} ${dateDay} ${dateYear} at ${dateHour}:${dateMinute < 10 ? '0' + dateMinute : dateMinute}`

      const promise = new Promise((resolve, reject) => {
         if (typeof newPost.img !== 'string') {

            // переводим картинку в 64 байтный формат
            const reader = new FileReader();
            reader.readAsDataURL(newPost.img)
            reader.onloadend = () => {
               postData.img = reader.result
               resolve()
            }
         } else {
            postData.img = ''
            resolve()
         }

      })
         .then(async () => {
            setIsLoading(true)

            try {
               const createPhotoBase = await fetch(`${process.env.REACT_APP_SERVER_PATH}api/post`, {
                  method: 'POST',
                  body: JSON.stringify(postData),
                  headers: { 'content-type': 'application/json' }
               })

               // получаем от сервера обновленный массив с постами, и его передаем в стейт
               const userPosts = await createPhotoBase.json()

               setAllPosts([...userPosts])
               setNewPost({ ...newPost, text: "", img: "" })
            } catch (e) {
               console.log(e)
            }

            setIsLoading(false)
         })
   }

   return (
      <div className="page__posts-new posts-new">
         {
            !isLoading
               ?
               <form onSubmit={e => createPost(e)} className="posts-new__form">
                  <div className="posts-new__text-container">
                     <textarea
                        onChange={e => setNewPost({ ...newPost, text: e.target.value })}
                        value={newPost.text} className="posts-new__text"
                        placeholder="Write something..."
                        required
                        style={{ height: areaHeight + 'px' }}
                     >
                     </textarea>
                     <div ref={heightClone} className="posts-new__text-clone">{newPost.text}</div>
                  </div>
                  <div className="posts-new__buttons">
                     <div className="posts-new__photo">
                        <input type="file" name="file" id="newPost_photo"
                           className="posts-new__photo-input" accept="image/jpeg"
                           onChange={e => setNewPost({ ...newPost, img: e.target.files[0] })} />
                        <label htmlFor="newPost_photo"
                           className={newPost.img ? "posts-new__photo-button _active" : "posts-new__photo-button"}>
                        </label>
                     </div>
                     <button type="submit" className="posts-new__publish-button">Publish</button>
                  </div>
               </form>
               :
               <div id="floatingCirclesG">
                  <div className="f_circleG" id="frotateG_01"></div>
                  <div className="f_circleG" id="frotateG_02"></div>
                  <div className="f_circleG" id="frotateG_03"></div>
                  <div className="f_circleG" id="frotateG_04"></div>
                  <div className="f_circleG" id="frotateG_05"></div>
                  <div className="f_circleG" id="frotateG_06"></div>
                  <div className="f_circleG" id="frotateG_07"></div>
                  <div className="f_circleG" id="frotateG_08"></div>
               </div>}
      </div>
   );
}

export default NewPost;