import Like from './Like';
import { Link } from 'react-router-dom';

let News = ({ newsInfo }) => {


   return (
      <div className="posts-all__item posts-item">
         <div className="posts-item__top">
            <Link to={`/page/${newsInfo.username}`}>
               <div className="posts-item__person">
                  <div className="posts-item__avatar">
                     <img src={`https://res.cloudinary.com/daggdfi3i/image/upload/${newsInfo?.img_user}.jpg`} className="posts-item__avatar-img" alt="news-post" />
                  </div>
                  <div className="posts-item__name">
                     <p className="posts-item__forename">{newsInfo.name}</p>
                     <p className="posts-item__surname">{newsInfo.surname}</p>
                  </div>
               </div>
            </Link>
            <div className="posts-item__data">{newsInfo.date}</div>
         </div>
         <div className="posts-item__content">
            <p className="posts-item__text">{newsInfo.text}</p>
            {
               newsInfo.img_post.length
                  ?
                  <div className="posts-item__img-container">
                     <img src={`https://res.cloudinary.com/daggdfi3i/image/upload/${newsInfo?.img_post}.jpg`} className="posts-item__img" alt="news-pic" />
                  </div>
                  :
                  null
            }
         </div>
         <div className="posts-item__bottom">
            <Like newsInfo={newsInfo} />
         </div>
      </div>
   );
}

export default News;