import './PhotosPage.scss'
import { useEffect, useState, Fragment } from 'react';
import { useSelector } from 'react-redux';
import Photo from '../../components/PhotosPage/Photo';

const PhotosPage = () => {

   const userData = useSelector((state) => state.userReducer.userParams)
   const [isLoading, setIsLoading] = useState(false)
   const [allPhotos, setAllPhotos] = useState([])

   // загружаем фото при монтировании компонента
   useEffect(() => {
      if (userData.id) {
         setIsLoading(true)

         fetch(`${process.env.REACT_APP_SERVER_PATH}api/photos/${userData.id}`)
            .then(res => res.json())
            .then(getData => setAllPhotos([...getData]))
            .catch(e => console.log(e))
            .finally(() => setIsLoading(false))

      }
   }, [userData.id])

   const createPhoto = (file) => {

      const newPhoto = {
         img: '',
         user_id: userData.id
      }

      const promise = new Promise((resolve, reject) => {
         const reader = new FileReader();
         reader.readAsDataURL(file)
         reader.onloadend = () => {
            newPhoto.img = reader.result
            resolve()
         }
      })
         .then(async () => {
            setIsLoading(true)

            try {
               const createPhotoBase = await fetch(`${process.env.REACT_APP_SERVER_PATH}api/photos`, {
                  method: 'POST',
                  body: JSON.stringify(newPhoto),
                  headers: { 'content-type': 'application/json' }
               })

               // получаем от сервера обновленный массив с постами, и его передаем в стейт
               const userPhotos = await createPhotoBase.json()
               setAllPhotos([...userPhotos])

            } catch (e) {
               console.log(e)
            }

            setIsLoading(false)
         })

   }

   return (
      <div className="main__content photos">
         <div className="photos__container">
            <p className="photos__title">My photos</p>
            {
               !isLoading
                  ?
                  <Fragment>
                     <form onSubmit={(e) => e.preventDefault()} className="photos__form">
                        <div className="photos__input-container">
                           <input onChange={(e) => createPhoto(e.target.files[0])} type="file" name="file" id="photos__input-file" className="photos__input" accept="image/jpeg,image/png" />
                           <label htmlFor="photos__input-file" className="photos__input-label">Add photos</label>
                        </div>
                     </form>
                     {
                        // есть фото или нет, показывает нужные блоки
                        allPhotos.length > 0
                           ?
                           <div className="photos__items">
                              {
                                 allPhotos.map((item) => {
                                    return (
                                       <Photo
                                          key={item.img}
                                          photoData={item}
                                          setAllPhotos={setAllPhotos}
                                          setIsLoading={setIsLoading}
                                       />
                                    )
                                 })
                              }
                           </div>
                           :
                           <div className="photos__empty">
                              <div className="photos__empty-icon">
                                 <img src="images/photos.png" className="photos__empty-img" alt="empty-pic" />
                              </div>
                              <p className="photos__empty-title">No photos yet 🙁</p>
                           </div>
                     }
                  </Fragment>
                  :
                  <div id="floatingCirclesG">
                     <div className="f_circleG" id="frotateG_01"></div>
                     <div className="f_circleG" id="frotateG_02"></div>
                     <div className="f_circleG" id="frotateG_03"></div>
                     <div className="f_circleG" id="frotateG_04"></div>
                     <div className="f_circleG" id="frotateG_05"></div>
                     <div className="f_circleG" id="frotateG_06"></div>
                     <div className="f_circleG" id="frotateG_07"></div>
                     <div className="f_circleG" id="frotateG_08"></div>
                  </div>
            }
         </div>
      </div>
   );
}

export default PhotosPage;