import { useState, useEffect, useRef } from 'react';
import { useSelector } from 'react-redux';

let WriteMessage = ({ chatId, userId, messages, setMessages }) => {

   const userData = useSelector((state) => state.userReducer.userParams);

   const [newMessage, setNewMessage] = useState('')
   const [areaHeight, setAreaHeight] = useState(45)
   const textarea = useRef()
   const heightClone = useRef()

   useEffect(() => {

      if (heightClone.current.clientHeight > 220) {
         textarea.current.style.overflow = 'auto';
         return
      }

      if (newMessage === '') {
         setAreaHeight(45)
         textarea.current.style.overflow = 'hidden';
      }

      if (heightClone.current.clientHeight > 45) {
         setAreaHeight(heightClone.current.clientHeight)
      }


   }, [newMessage])

   const createMessage = async (e) => {
      e.preventDefault()

      const messageData = {
         chat_id: chatId,
         text: newMessage,
         user_id: userId,
      }

      let dateMonth = new Date().toDateString().substr(4, 3)
      let dateDay = new Date().getDate();
      let dateYear = new Date().getFullYear();
      let dateHour = new Date().getHours();
      let dateMinute = new Date().getMinutes();

      messageData.date = `${dateMonth} ${dateDay} ${dateYear} at ${dateHour}:${dateMinute < 10 ? '0' + dateMinute : dateMinute}`

      try {
         //создание нового сообщения в базе данных по шаблону newForm
         const createMessageBase = await fetch(`${process.env.REACT_APP_SERVER_PATH}api/messages`, {
            method: 'POST',
            headers: {
               'Content-Type': 'application/json;charset=utf-8'
            },
            body: JSON.stringify(messageData)
         })

         setNewMessage('')
      } catch (e) {
         alert(e)
      }
   }

   return (
      <div className="message__bottom">
         <div className="message__new message-new">
            <form onSubmit={e => createMessage(e)} className="message-new__form">
               <div className="message-new__text-container">
                  <textarea
                     className="message-new__text"
                     onChange={e => setNewMessage(e.target.value)}
                     value={newMessage}
                     placeholder="Write something..."
                     required
                     style={{ height: areaHeight + 'px' }}
                     ref={textarea}
                  ></textarea>
                  <div ref={heightClone} className="message-new__text-clone">{newMessage}</div>
               </div>
               <button type="submit" className="message-new__send-button">Send</button>
            </form>
         </div>
      </div>
   );
}

export default WriteMessage;