import { Fragment } from 'react';
import Request from './Request';

let AllRequests = ({ friendsList, setFriendsList }) => {

   return (
      <Fragment >
         {
            friendsList.requests.length
               ?
               <div className="friends__requests">
                  <p className="friends__requests-title">Friend requests</p>
                  {
                     friendsList.requests.map((item) => {
                        return (
                           <Request
                              requestData={item}
                              friendsList={friendsList}
                              setFriendsList={setFriendsList}
                              key={item.img}
                           />
                        )
                     })
                  }
               </div>
               :
               null
         }
      </Fragment>
   );
}

export default AllRequests;