import './SearchPage.scss';
import { useState, Fragment } from 'react';
import Search from '../../components/SearchPage/Search';
import FoundUser from '../../components/SearchPage/FoundUser';

let SearchPage = () => {

   const [isLoading, setIsLoading] = useState(false)
   const [foundUsers, setFoundUsers] = useState([])

   return (
      <div className="main__content search">
         <p className="search__title">Search people</p>
         {
            !isLoading
               ?
               <Fragment>
                  <Search
                     foundUsers={foundUsers}
                     setFoundUsers={setFoundUsers}
                     setIsLoading={setIsLoading}
                  />

                  {
                     !foundUsers.length
                        ?
                        <div className="search__empty">
                           <div className="search__empty-icon">
                              <img src="./images/search.png" className="search__empty-img" alt="Empty search" />
                           </div>
                           <p className="search__empty-title">Find your friend 🧐</p>
                        </div>
                        :
                        <div className="search__items">
                           {
                              foundUsers.map((i) => {
                                 return (
                                    <FoundUser userInfo={i} key={i.img} />
                                 )
                              })
                           }
                        </div>
                  }
               </Fragment>
               :
               <div id="floatingCirclesG">
                  <div className="f_circleG" id="frotateG_01"></div>
                  <div className="f_circleG" id="frotateG_02"></div>
                  <div className="f_circleG" id="frotateG_03"></div>
                  <div className="f_circleG" id="frotateG_04"></div>
                  <div className="f_circleG" id="frotateG_05"></div>
                  <div className="f_circleG" id="frotateG_06"></div>
                  <div className="f_circleG" id="frotateG_07"></div>
                  <div className="f_circleG" id="frotateG_08"></div>
               </div>
         }

      </div>
   );
}

export default SearchPage;