import { useSelector } from 'react-redux';
import { Link } from 'react-router-dom';
import MessageButton from '../UI/MessageButton/MessageButton';

let Friend = ({ friendData, friendsList, setFriendsList }) => {

   const userData = useSelector((state) => state.userReducer.userParams)

   const deleteFriend = () => {
      fetch(`${process.env.REACT_APP_SERVER_PATH}api/friend?user_id=${userData.id}&friend_id=${friendData.id}`, { method: 'DELETE', })
         .then(res => res.json())
         .then(getData => setFriendsList({ ...friendsList, friends: [...getData.friends] }))
         .catch(e => alert(e))
   }

   return (
      <div className="friends__item friends-item">
         <div className="friends-item__content">
            <Link to={`/page/${friendData.username}`} className='friends-item__link'>
               <div className="friends-item__avatar">
                  <img src={`https://res.cloudinary.com/daggdfi3i/image/upload/${friendData.img}`} className="friends-item__avatar-img" alt="friend-avatar" />
               </div>
            </Link>
            <div className="friends-item__text">
               <div className="friends-item__name">
                  <p className="friends-item__forename">{friendData.name}</p>
                  <p className="friends-item__surname">{friendData.surname}</p>
               </div>
               <MessageButton
                  data={friendData}
                  classTitle={'friends-item__message'}
                  typeName={'button'}
               />
            </div>
         </div>
         <div onClick={() => deleteFriend()} className="friends-item__delete"></div>
      </div>
   );
}

export default Friend;