import Photo from './Photo';
import { useEffect } from 'react';

let AllPhotos = ({ userInfo, allPhotos, setAllPhotos }) => {

   useEffect(() => {
      if (userInfo.id) {
         fetch(`${process.env.REACT_APP_SERVER_PATH}api/photos/${userInfo.id}`)
            .then(res => res.json())
            .then(getData => setAllPhotos([...getData]))
            .catch(e => console.log(e))
      }
   }, [userInfo.id])

   return (
      <div className="person-info__row person-info__row-4">
         {
            allPhotos.length
               ?
               <div className="person-info__photos">
                  {
                     allPhotos.map((item, index) => {
                        // отображаем только первые 4 фотографии на странице
                        if (index < 4) {
                           return (
                              <Photo key={item.img} photoData={item} />
                           )
                        }
                     })
                  }
               </div>
               : null
         }
      </div>
   );
}

export default AllPhotos;