
const Photo = ({ photoData, setAllPhotos, setIsLoading }) => {

   // логика кнопки по удалению фото
   const deletePhoto = async () => {

      try {
         setIsLoading(true)

         const deleteRequest = await fetch(`${process.env.REACT_APP_SERVER_PATH}api/photos/${photoData.id}`, { method: 'DELETE' })
         const getPhotos = await deleteRequest.json()
         setAllPhotos([...getPhotos])

         setIsLoading(false)

      } catch (error) {
         console.log(error)
      }
   }

   return (
      <div className="photos__item">
         <div onClick={() => deletePhoto()} className="photos__delete"></div>
         <img src={`https://res.cloudinary.com/daggdfi3i/image/upload/${photoData?.img}.jpg`} className="photos__img" alt="My album" />
      </div>
   );
}

export default Photo;