import { useEffect, useState } from 'react';
import { useSelector } from 'react-redux';
import Photo from './Photo';

const AllPhotos = ({ allPhotos, setAllPhotos }) => {

   const userData = useSelector((state) => state.userReducer.userParams)
   const [isLoading, setIsLoading] = useState(false)

   useEffect(() => {
      if (userData.id) {
         fetch(`${process.env.REACT_APP_SERVER_PATH}api/photos/${userData.id}`)
            .then(res => res.json())
            .then(getData => setAllPhotos([...getData]))
            .catch(e => console.log(e))
      }
   }, [userData.id])

   const createPhoto = async (file) => {
      const newPhoto = {}
      newPhoto.user_id = userData.id

      const promise = new Promise((resolve, reject) => {

         // переводим картинку в 64 байтный формат
         const reader = new FileReader();
         reader.readAsDataURL(file)
         reader.onloadend = () => {
            newPhoto.img = reader.result
            resolve()
         }
      })
         .then(async () => {
            setIsLoading(true)

            try {
               const createPhotoBase = await fetch(`${process.env.REACT_APP_SERVER_PATH}api/photos`, {
                  method: 'POST',
                  body: JSON.stringify(newPhoto),
                  headers: { 'content-type': 'application/json' }
               })

               // получаем от сервера обновленный массив с постами, и его передаем в стейт
               let userPhotos = await createPhotoBase.json()
               setAllPhotos([...userPhotos])

               setIsLoading(false)
            } catch (e) {
               setIsLoading(false)
               console.log(e)
            }
         })
   }

   return (
      <div className="page-info__row page-info__row-4">
         {
            allPhotos.length
               ?
               <div className="page-info__photos">
                  {
                     allPhotos.map((item, index) => {
                        // отображаем только первые 4 фотографии на странице из общего стейта фото
                        if (index < 4) {
                           return (
                              <Photo key={item.img} photoData={item} />
                           )
                        }
                     })
                  }
               </div>
               : null
         }
         {
            !isLoading
               ?
               <form onSubmit={(e) => e.preventDefault()} className="page-info__photos-form">
                  <div className="page-info__input-container">
                     <input onChange={(e) => createPhoto(e.target.files[0])} type="file" name="file" id="input__file" className="page-info__input" accept="image/jpeg,image/png" />
                     <label htmlFor="input__file" className="page-info__input-label">Add photos</label>
                  </div>
               </form>
               :
               <div id="floatingCirclesG">
                  <div className="f_circleG" id="frotateG_01"></div>
                  <div className="f_circleG" id="frotateG_02"></div>
                  <div className="f_circleG" id="frotateG_03"></div>
                  <div className="f_circleG" id="frotateG_04"></div>
                  <div className="f_circleG" id="frotateG_05"></div>
                  <div className="f_circleG" id="frotateG_06"></div>
                  <div className="f_circleG" id="frotateG_07"></div>
                  <div className="f_circleG" id="frotateG_08"></div>
               </div>
         }
      </div>
   );
}

export default AllPhotos;