import { useSelector } from 'react-redux';

let Message = ({ messageInfo, interlocutorData }) => {

   const userData = useSelector((state) => state.userReducer.userParams)

   return (
      <div className="message__item message-item">
         <div className="message-item__avatar">
            <img
               src={`https://res.cloudinary.com/daggdfi3i/image/upload/${userData.id === messageInfo.user_id ? userData.img : interlocutorData.img}.jpg`}
               className="message-item__avatar-img"
               alt="Message person avatar"
            />
         </div>
         <div className="message-item__text">
            <div className="message-item__info">
               <p className="message-item__name">
                  {userData.id === messageInfo.user_id ? userData.name : interlocutorData.name}
               </p>
               <p className="message-item__date">{messageInfo.date}</p>
            </div>
            <p className="message-item__message-text">{messageInfo.text}</p>
         </div>
      </div>
   );
}

export default Message;