import { useSelector } from 'react-redux';
import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import MessageButton from '../UI/MessageButton/MessageButton';

const FoundUser = ({ userInfo }) => {

   const userData = useSelector((state) => state.userReducer.userParams)
   const [friendStatus, setFriendStatus] = useState('')

   //получаем статус дружбы для текущего юзера по отношению к данной странице пользователя
   useEffect(async () => {
      try {

         if (Object.keys(userInfo).length && Object.keys(userData).length) {
            const requestFriendStatus = await fetch(`${process.env.REACT_APP_SERVER_PATH}api/friend/status?user_id=${userData.id}&friend_id=${userInfo.id}`)
            const status = await requestFriendStatus.json()
            setFriendStatus(status)
         }

      } catch (e) {
         console.log(e)
      }
   }, [userData, userInfo])

   const handlerFriend = async () => {
      if (userData.id) {
         // при отправке заявки в друзья, когда еще не созданы данные
         if (!friendStatus.length) {

            const newFriend = {
               user_id: userData.id,
               friend_id: userInfo.id
            }

            try {
               const createFriendBase = await fetch(`${process.env.REACT_APP_SERVER_PATH}api/friend`, {
                  method: 'POST',
                  headers: { 'Content-Type': 'application/json' },
                  body: JSON.stringify(newFriend)
               })

               const friendStatus = await createFriendBase.json()
               setFriendStatus(friendStatus)
            } catch (e) {
               console.log(e)
            }

         } else if (friendStatus === 'request') {
            // логика когда ты принимаешь заявку в друзья. Меняется статус дружбы в таблице на сервере
            const newStatus = {
               user_id: userData.id,
               friend_id: userInfo.id,
               status: 'friend'
            }

            try {
               const updateStatus = await fetch(`${process.env.REACT_APP_SERVER_PATH}api/friend/status`, {
                  method: 'PUT',
                  headers: { 'Content-Type': 'application/json' },
                  body: JSON.stringify(newStatus)
               })

               const friendStatus = await updateStatus.json()
               setFriendStatus(friendStatus)

            } catch (e) {
               console.log(e)
            }
         }
      }
   }

   return (
      <div className="search__item search-item">
         <div className="search-item__name">
            <p className="search-item__forname">{userInfo.name}</p>
            <p className="search-item__surname">{userInfo.surname}</p>
         </div>
         <Link to={`/page/${userInfo.username}`}>
            <div className="search-item__avatar">
               <img src={`https://res.cloudinary.com/daggdfi3i/image/upload/${userInfo.img}.jpg`} className="search-item__avatart-img" alt="Found profile"></img>
            </div>
         </Link>
         <div className="search-item__buttons">
            <MessageButton
               data={userInfo}
               classTitle={'search-item__button-message'}
               typeName={'button'}
            />
            <button onClick={() => handlerFriend()} className={!friendStatus.length ? "search-item__button-add" : `search-item__button-add _${friendStatus}`}></button>
         </div>
      </div>
   );
}

export default FoundUser;