import { useDispatch } from 'react-redux';
import { useState, useEffect, Fragment } from 'react';
import './AuthorizationPage.scss';
import RegisterForm from '../../components/AuthorizationPage/RegisterForm';
import AuthorizationForm from '../../components/AuthorizationPage/AuthorizationForm';

let AuthorizationPage = () => {

   const dispatch = useDispatch()

   const [loading, setLoading] = useState(false)
   const [tabsState, tabsStateHandler] = useState({
      register: false,
      auth: false,
   })

   // логика кнопок-табов для переключения между регистр и авториз
   let tabsHandler = (elem) => {
      let tabsFake = { ...tabsState }
      let tabsKeys = Object.keys(tabsFake);
      tabsKeys.forEach((e) => {
         if (e === elem) {
            tabsFake[e] = true
         } else {
            tabsFake[e] = false
         }
      })
      tabsStateHandler({ ...tabsFake })
   }

   useEffect(() => {
      tabsStateHandler({ register: false, auth: true, })
      if (localStorage.getItem('username')) {
         dispatch({ type: "CHANGE_AUTHO" })
      }
   }, [])

   return (
      <div className='wrapper'>
         <div className="main">
            <div className="main__content entry">
               <div className="entry__container">
                  <div className="entry__introduction entry-introduction">
                     <p className="entry-introduction__title">Welcome to</p>
                     <div className="entry-introduction__logo">
                        <div className="entry-introduction__logo-icon"></div>
                        <p className="entry-introduction__logo-text">Social network</p>
                     </div>
                  </div>

                  {
                     !loading
                        ?
                        <Fragment>
                           <div className="entry__buttons">
                              <button className="entry__register" onClick={() => tabsHandler('register')}>Register</button>
                              <button className="entry__sign-in" onClick={() => tabsHandler('auth')}>Sign in</button>
                           </div>

                           <div className="entry__form-container">
                              <RegisterForm
                                 tabsState={tabsState}
                                 loading={loading}
                                 setLoading={setLoading}
                              />

                              <AuthorizationForm
                                 tabsState={tabsState}
                                 setLoading={setLoading}
                              />
                           </div>
                        </Fragment>
                        :
                        <div id="floatingCirclesG">
                           <div className="f_circleG" id="frotateG_01"></div>
                           <div className="f_circleG" id="frotateG_02"></div>
                           <div className="f_circleG" id="frotateG_03"></div>
                           <div className="f_circleG" id="frotateG_04"></div>
                           <div className="f_circleG" id="frotateG_05"></div>
                           <div className="f_circleG" id="frotateG_06"></div>
                           <div className="f_circleG" id="frotateG_07"></div>
                           <div className="f_circleG" id="frotateG_08"></div>
                        </div>
                  }

               </div>
            </div>
         </div>
      </div >
   );
}

export default AuthorizationPage;