import './ChatPage.scss';
import { useState, useEffect } from 'react';
import { useSelector } from 'react-redux';
import Message from '../../components/ChatPage/Message';
import WriteMessage from '../../components/ChatPage/WriteMessage';

const ChatPage = () => {

   const userData = useSelector((state) => state.userReducer.userParams)

   // контроллеры для отмены fetch запроса
   const controller = new AbortController();
   const signal = controller.signal;

   // вырезаем id чата из строки url адреса
   const chatId = document.location.pathname.slice(10)

   const [messages, setMessages] = useState([])
   const [interlocutorData, setInterlocutor] = useState({})

   // получаем все сообщения
   useEffect(() => {
      if (userData.id) {
         // передаем на сервер номер чата и текущего пользователя страницы
         fetch(`${process.env.REACT_APP_SERVER_PATH}api/messages?chat_id=${chatId}&user_id=${userData.id}`)
            .then(res => res.json())
            .then(getData => {
               // в ответе с сервера получаем объект с данными собеседника, и массив с сообщениями
               setInterlocutor({ ...getData[0] })
               setMessages([...getData[1]])
            })
            .catch(e => alert(e))
      }
   }, [userData])

   // подписываемся на long-polling
   useEffect(() => {
      subscribe()
      const showAbort = () => { () => console.log('Отмена') }
      signal.addEventListener('abort', showAbort);

      // при размонтировании компонента (ухода со страницы) отписываемся от обработчиков событий и прерываем long polling
      return () => {
         controller.abort();
         signal.removeEventListener('abort', showAbort);
      }
   }, [])

   const subscribe = async () => {
      try {
         const getMessage = await fetch(`${process.env.REACT_APP_SERVER_PATH}api/message-one/${chatId}`, {
            signal: controller.signal
         })

         const newMessage = await getMessage.json()
         // console.log(newMessage)
         setMessages((prev) => [...prev, newMessage])
         await subscribe()
      } catch (error) {
         // если причина ошибки - отмена через AbortController, то делаем снова запрос на сервер
         if (error.message !== 'The user aborted a request.') {
            setTimeout(() => {
               subscribe()
            }, 500)
         }
      }
   }

   return (
      <div className="main__content message">
         <div className="message__container">
            <div className="message__top">
               <div className="message__avatar">
                  <img src={interlocutorData.img ? `https://res.cloudinary.com/daggdfi3i/image/upload/${interlocutorData.img}.jpg` : null} className="message__avatar-img" alt="Message avatart" />
               </div>
               <div className="message__name">
                  <p className="message__forename">{interlocutorData.name}</p>
                  <p className="message__surname">{interlocutorData.surname}</p>
               </div>
            </div>
            {
               messages.length
                  ?
                  <div className="message__items">
                     {
                        messages.map((i) => {
                           return (
                              <Message
                                 messageInfo={i}
                                 interlocutorData={interlocutorData}
                                 key={i.id}
                              />
                           )
                        })
                     }
                  </div>
                  :
                  <div className="message__empty">
                     <div className="message__empty-icon">
                        <img src="../images/write.png" className="message__empty-img" alt="Message empty" />
                     </div>
                     <p className="message__empty-title">Start communicating 😉</p>
                  </div>
            }
            <WriteMessage
               chatId={chatId}
               userId={userData.id}
               messages={messages}
               setMessages={setMessages}
            />
         </div>
      </div>
   );
}

export default ChatPage;