import { Fragment } from 'react';
import Friend from './Friend';

let AllFriends = ({ friendsList, setFriendsList }) => {

   return (
      <Fragment>
         {
            friendsList.friends.length
               ?
               <div className="friends__all">
                  {
                     friendsList.friends.map((item) => {
                        return (
                           <Friend
                              friendData={item}
                              friendsList={friendsList}
                              setFriendsList={setFriendsList}
                              key={item.img}
                           />
                        )
                     })
                  }
               </div>
               :
               null
         }
      </Fragment>
   );
}

export default AllFriends;