const authoState = {
   authorization: false
}

// функция которая изменяет наш redux-стейт по написанной логике. Данные берутся из переданного action
export const authReducer = (state = authoState, action) => {
   switch (action.type) {
      case "CHANGE_AUTHO":
         return { ...state, authorization: !state.authorization }
      default:
         return state
   }
}