import './NewsPage.scss';
import { useState, useEffect, Fragment } from 'react';
import { useSelector } from 'react-redux';
import News from '../../components/NewsPage/News';

const NewsPage = () => {

   const userData = useSelector((state) => state.userReducer.userParams)

   const [allNews, setAllNews] = useState([])
   const [isLoading, setIsLoading] = useState(false)

   useEffect(() => {
      if (userData.id) {
         setIsLoading(true)

         fetch(`${process.env.REACT_APP_SERVER_PATH}api/news/${userData.id}`)
            .then(res => res.json())
            .then(getData => {
               const sortNews = getData.sort((a, b) => a.id - b.id)
               setAllNews([...sortNews])
            })
            .catch(e => console.log(e))
            .finally(() => setIsLoading(false))
      }
   }, [userData])

   return (
      <div className="main__content news">
         <div className="news__container">
            <p className="news__title">News</p>

            {
               !isLoading
                  ?
                  <Fragment>
                     {
                        !allNews.length
                           ?
                           <div className="posts-all__empty">
                              <div className="posts-all__empty-icon">
                                 <img src="./images/news.png" className="posts-all__empty-img" alt="empty-news" />
                              </div>
                              <p className="posts-all__empty-title">No news yet 🙁</p>
                           </div>
                           :
                           <div className="news__posts-all posts-all">
                              <div className="posts-all__items">
                                 {
                                    allNews.reverse().map((i) => {
                                       return (
                                          <News newsInfo={i} key={i.img_post} />
                                       )
                                    })
                                 }
                              </div>
                           </div>
                     }
                  </Fragment>
                  :
                  <div id="floatingCirclesG">
                     <div className="f_circleG" id="frotateG_01"></div>
                     <div className="f_circleG" id="frotateG_02"></div>
                     <div className="f_circleG" id="frotateG_03"></div>
                     <div className="f_circleG" id="frotateG_04"></div>
                     <div className="f_circleG" id="frotateG_05"></div>
                     <div className="f_circleG" id="frotateG_06"></div>
                     <div className="f_circleG" id="frotateG_07"></div>
                     <div className="f_circleG" id="frotateG_08"></div>
                  </div>
            }
         </div>
      </div>
   );
}

export default NewsPage;