import { useForm } from 'react-hook-form';
import { useDispatch } from 'react-redux';
import { CreateUserActionThunk } from '../../store/userReducer';

const RegisterForm = ({ tabsState, loading, setLoading }) => {

   const dispatch = useDispatch()

   const {
      register,
      watch,
      formState: { errors },
      handleSubmit,
   } = useForm({ mode: "onChange" });

   const watchImg = watch("img");

   const onSubmit = (data) => {

      const newUser = { ...data }

      // промис для того, чтобы отсылать запрос на сервер только при завершении кодирования в 64 формат картинки
      const promise = new Promise((resolve, reject) => {
         // переводим картинку в 64 байтный формат
         const reader = new FileReader();
         reader.readAsDataURL(newUser.img[0])
         reader.onloadend = () => {
            newUser.img = reader.result
            resolve()
         }
      })
         .then(() => {
            setLoading(!loading)

            dispatch(CreateUserActionThunk(newUser))
         })
   }

   return (
      <form onSubmit={handleSubmit(onSubmit)} className={tabsState.register ? "entry__form-register form-register _active" : "entry__form-register form-register"}>

         <label className='form-register__label'>
            Username
            <input
               {...register('username', {
                  required: true,
                  pattern: { value: /^[0-9a-z]+$/, message: "Некорректные символы." },
                  minLength: { value: 4, message: "Минимум 4 символа." },
                  maxLength: { value: 10, message: "Максимум 10 символов" }
               })}
               className='form-register__input' type="text" placeholder="Example: sun144"
            />
            <p className={`form-register__error ${errors.username ? '_active' : null}`}>
               {errors?.username?.message || 'Обязательное поле для ввода.'}
            </p>
         </label>

         <label className='form-register__label'>
            Name
            <input
               {...register('name', {
                  required: true,
                  pattern: { value: /^[a-zA-Z]+$/, message: "Некорректные символы." },
                  maxLength: { value: 20, message: "Максимум 20 символов" }
               })}
               className='form-register__input' type="text" placeholder="Example: John"
            />
            <p className={`form-register__error ${errors.name ? '_active' : null}`}>
               {errors?.name?.message || 'Обязательное поле для ввода.'}
            </p>
         </label>

         <label className='form-register__label'>
            Surname
            <input
               {...register('surname', {
                  required: true,
                  pattern: { value: /^[a-zA-Z]+$/, message: "Некорректные символы." },
                  maxLength: { value: 20, message: "Максимум 20 символов" }
               })}
               className='form-register__input' type="text" placeholder="Example: Lingard"
            />
            <p className={`form-register__error ${errors.surname ? '_active' : null}`}>
               {errors?.surname?.message || 'Обязательное поле для ввода.'}
            </p>
         </label>

         <label className='form-register__label'>
            Date of birth
            <input
               {...register('birth', {
                  required: true,
               })}
               className='form-register__input' type="date" min="1960-01-01" max="2015-01-01"
            />
            <p className={`form-register__error ${errors.birth ? '_active' : null}`}>
               {errors?.birth?.message || 'Обязательное поле для ввода.'}
            </p>
         </label>

         <label className='form-register__label'>
            City
            <input
               {...register('city', {
                  required: true,
                  pattern: { value: /^[a-zA-Z]+$/, message: "Некорректные символы." },
                  maxLength: { value: 20, message: "Максимум 20 символов" }
               })}
               className='form-register__input' type="text" placeholder="Example: London"
            />
            <p className={`form-register__error ${errors.city ? '_active' : null}`}>
               {errors?.city?.message || 'Обязательное поле для ввода.'}
            </p>
         </label>

         <div className={watchImg?.length ? 'form-register__photo-container _active' : 'form-register__photo-container'}>
            <label className='form-register__photo-label'>
               Add photo
               <input
                  {...register('img', {
                     required: true,
                  })}
                  className='form-register__photo-input' type="file" accept="image/jpeg"
               />
            </label>
            <p className={`form-register__error ${errors.img ? '_active' : null}`}>
               {errors?.img?.message || 'Обязательное поле для ввода.'}
            </p>
         </div>

         <label className='form-register__label'>
            Password
            <input
               {...register('password', {
                  required: true,
                  pattern: { value: /^[a-zA-Z0-9]+$/, message: "Некорректные символы." },
                  minLength: { value: 6, message: "Минимум 6 символов" },
                  maxLength: { value: 20, message: "Максимум 20 символов" }
               })}
               className='form-register__input' type="password" placeholder="Example: bend12AW"
            />
            <p className={`form-register__error ${errors.password ? '_active' : null}`}>
               {errors?.password?.message || 'Обязательное поле для ввода.'}
            </p>
         </label>

         <button type='submit' className="form-register__button-submit">REGISTRATION</button>
      </form >
   );
}

export default RegisterForm;