import { useEffect } from 'react';
import Post from './Post';

let AllPosts = ({ userInfo, allPosts, setAllPosts }) => {

   useEffect(() => {
      if (userInfo.id) {
         fetch(`${process.env.REACT_APP_SERVER_PATH}api/post/${userInfo.id}`)
            .then(res => res.json())
            .then(getData => setAllPosts([...getData]))
            .catch(e => console.log(e))
      }
   }, [userInfo])

   return (
      <div className="person__posts-all posts-all">
         {
            allPosts.length
               ?
               allPosts.map((item) => {
                  return (
                     <Post key={item.img_post} postData={item} />
                  )
               })
               :
               <div className="posts-all__empty">
                  <div className="posts-all__empty-icon">
                     <img src="icon/write.png" className="posts-all__empty-img" alt="Page empty" />
                  </div>
                  <p className="posts-all__empty-title">No posts yet 🙁</p>
               </div>
         }

      </div>
   );
}

export default AllPosts;