import { useSelector } from 'react-redux';
import { useNavigate } from 'react-router';

const MessageButton = ({ data, typeName, classTitle }) => {

   const navigate = useNavigate()
   const userData = useSelector((state) => state.userReducer.userParams)

   const joinChat = async () => {
      try {
         const joinChat = await fetch(`https://deploy-social.herokuapp.com/api/chat/join?user_id=${userData.id}&interlocutor_id=${data.id}`)
         const chatId = await joinChat.json()
         navigate(`/messages/${chatId}`)
      } catch (e) {
         alert(e)
      }
   }

   return (
      <button onClick={() => joinChat()} type={typeName} className={classTitle}>Write</button>
   );
}

export default MessageButton;