import './FriendsPage.scss'
import { useState, useEffect, Fragment } from 'react';
import { useSelector } from 'react-redux';
import AllFriends from '../../components/FriendsPage/AllFriends';
import AllRequests from '../../components/FriendsPage/AllRequests';

const FriendsPage = () => {

   const userData = useSelector((state) => state.userReducer.userParams)
   // друзья и запросы в друзья
   const [friendsList, setFriendsList] = useState({
      requests: [],
      friends: []
   })

   useEffect(() => {
      if (userData.id) {
         fetch(`${process.env.REACT_APP_SERVER_PATH}api/friend/${userData.id}`)
            .then(res => res.json())
            .then(getData => {
               // setFriendsList({ ...getData })
               setFriendsList({ ...friendsList, requests: [...getData.requests], friends: [...getData.friends] })
            })
            .catch(e => alert(e))
      }
   }, [userData])

   return (
      <div className="main__content friends">
         <div className="friends__container">
            <p className="friends__title">My friends</p>

            {
               !friendsList.friends.length && !friendsList.requests.length
                  ?
                  <div className="friends__empty">
                     <div className="friends__empty-icon">
                        <img src="./images/frinbed.png" className="friends__empty-img" alt="empty-pic" />
                     </div>
                     <p className="friends__empty-title">No friends yet 🙁</p>
                  </div>
                  :
                  <Fragment>
                     <AllRequests
                        friendsList={friendsList}
                        setFriendsList={setFriendsList}
                     />

                     <AllFriends
                        friendsList={friendsList}
                        setFriendsList={setFriendsList}
                     />
                  </Fragment>
            }
         </div>
      </div>
   );
}

export default FriendsPage;