import { useState, useEffect } from 'react';
import { useSelector } from 'react-redux';
import AllPhotos from './AllPhotos';

let Info = ({ allPosts, allPhotos, setAllPhotos }) => {

   let userData = useSelector((state) => state.userReducer.userParams)

   const [friends, setFriend] = useState(0)
   const [likes, setLikes] = useState(0)

   useEffect(async () => {
      if (userData.id) {
         try {
            await fetch(`${process.env.REACT_APP_SERVER_PATH}api/friend/${userData.id}`)
               .then(res => res.json())
               .then(getData => setFriend(getData.friends.length))
               .catch(e => console.log(e))

            await fetch(`${process.env.REACT_APP_SERVER_PATH}api/user/likes/${userData.id}`)
               .then(res => res.json())
               .then(getData => setLikes(getData.length))
               .catch(e => console.log(e))
         } catch (e) {
            console.log(e)
         }
      }
   }, [userData.id])

   return (
      <div className="page__info page-info">
         <div className="page-info__row page-info__row-1">
            <div className="page-info__name">
               <p className="page-info__forename">{userData.name}</p>
               <p className="page-info__surname">{userData.surname}</p>
            </div>
            <div className="page-info__id">id: {userData.username}</div>
         </div>
         <div className="page-info__row page-info__row-2">
            <div className="page-info__age">
               <p className="page-info__age-title">Date of birth: </p>
               <div className="page-info__age-data">
                  <p className="page-info__age-year">{userData.birth ? userData.birth.slice(0, 4) : ''} /&nbsp;</p>
                  <p className="page-info__age-month">{userData.birth ? userData.birth.slice(5, 7) : ''} /&nbsp;</p>
                  <p className="page-info__age-day">{userData.birth ? userData.birth.slice(8, 10) : ''}</p>
               </div>
            </div>
            <div className="page-info__city">
               <p className="page-info__city-title">City: </p>
               <p className="page-info__city-name">{userData.city}</p>
            </div>
         </div>
         <div className="page-info__row page-info__row-3">
            <div className="page-info__item">
               <p className="page-info__item-value">{allPosts.length}</p>
               <p className="page-info__item-title">posts</p>
            </div>

            <div className="page-info__item">
               <p className="page-info__item-value">{friends}</p>
               <p className="page-info__item-title">friends</p>
            </div>

            <div className="page-info__item">
               <p className="page-info__item-value">{allPhotos.length}</p>
               <p className="page-info__item-title">photos</p>
            </div>

            <div className="page-info__item">
               <p className="page-info__item-value">{likes}</p>
               <p className="page-info__item-title">likes</p>
            </div>
         </div>
         <AllPhotos
            allPhotos={allPhotos}
            setAllPhotos={setAllPhotos}
         />
      </div>
   );
}

export default Info;