import { useNavigate } from 'react-router';

let Chat = ({ chatInfo, setChats, user_id }) => {

   const navigate = useNavigate()

   const openChat = () => {
      navigate(`/messages/${chatInfo.id}`)
   }

   const deleteChat = async (e) => {
      e.stopPropagation()

      const deleteChat = await fetch(`${process.env.REACT_APP_SERVER_PATH}api/chat`, {
         method: 'DELETE',
         headers: {
            'Content-Type': 'application/json;charset=utf-8'
         },
         body: JSON.stringify({
            user_id: user_id,
            chat_id: chatInfo.id
         }
         )
      })
      const allChats = await deleteChat.json()

      setChats([...allChats])
   }

   return (
      <div onClick={() => openChat()} className="messages__item messages-item">
         <div className="messages-item__content">
            <div className="messages-item__avatar">
               <img src={`https://res.cloudinary.com/daggdfi3i/image/upload/${chatInfo?.interlocutor_img}.jpg`} className="messages-item__avatar-img" alt="message-avatar" />
            </div>
            <div className="messages-item__text">
               <p className="messages-item__name">{chatInfo.interlocutor_name}:</p>
               <span className="messages-item__message">{chatInfo.text}</span>
            </div>
         </div>
         <div className="messages-item__info">
            <p className="messages-item__data">{chatInfo.date}</p>
            <div onClick={(e) => deleteChat(e)} className="messages-item__delete"></div>
         </div>
      </div>
   );
}

export default Chat;