import { useState, useEffect } from 'react';
import AllPhotos from './AllPhotos';

let Info = ({ userInfo, allPosts, allPhotos, setAllPhotos }) => {

   const [friends, setFriend] = useState(0)
   const [likes, setLikes] = useState(0)

   useEffect(async () => {
      if (userInfo.id) {

         try {

            await fetch(`${process.env.REACT_APP_SERVER_PATH}api/friend/${userInfo.id}`)
               .then(res => res.json())
               .then(getData => setFriend(getData.friends.length))

            await fetch(`${process.env.REACT_APP_SERVER_PATH}api/user/likes/${userInfo.id}`)
               .then(res => res.json())
               .then(getData => setLikes(getData.length))

         } catch (error) {
            console.log(error)
         }
      }
   }, [userInfo.id])

   return (
      <div className="person__info person-info">
         <div className="person-info__row person-info__row-1">
            <div className="person-info__name">
               <p className="person-info__forename">{userInfo.name}</p>
               <p className="person-info__surname">{userInfo.surname}</p>
            </div>
            <div className="person-info__username">id: {userInfo.username}</div>
         </div>
         <div className="person-info__row person-info__row-2">
            <div className="person-info__age">
               <p className="person-info__age-title">Date of birth: </p>
               <div className="person-info__age-data">
                  <p className="person-info__age-year">{userInfo.birth ? userInfo.birth.slice(0, 4) : ''} /&nbsp;</p>
                  <p className="person-info__age-month">{userInfo.birth ? userInfo.birth.slice(5, 7) : ''} /&nbsp;</p>
                  <p className="person-info__age-day">{userInfo.birth ? userInfo.birth.slice(8, 10) : ''}</p>
               </div>
            </div>
            <div className="person-info__city">
               <p className="person-info__city-title">City: </p>
               <p className="person-info__city-name">{userInfo.city}</p>
            </div>
         </div>
         <div className="person-info__row person-info__row-3">
            <div className="person-info__item">
               <p className="person-info__item-value">{allPosts.length}</p>
               <p className="person-info__item-title">posts</p>
            </div>

            <div className="person-info__item">
               <p className="person-info__item-value">{friends}</p>
               <p className="person-info__item-title">friends</p>
            </div>

            <div className="person-info__item">
               <p className="person-info__item-value">{allPhotos.length}</p>
               <p className="person-info__item-title">photos</p>
            </div>

            <div className="person-info__item">
               <p className="person-info__item-value">{likes}</p>
               <p className="person-info__item-title">likes</p>
            </div>
         </div>
         <AllPhotos
            userInfo={userInfo}
            allPhotos={allPhotos}
            setAllPhotos={setAllPhotos}
         />
      </div>
   );
}

export default Info;